    84→static int
    85→ldap_pvt_ndelay_on(LDAP *ld, int fd)
    86→{
    87→	Debug1(LDAP_DEBUG_TRACE, "ldap_ndelay_on: %d\n",fd );
    88→	return ber_pvt_socket_set_nonblock( fd, 1 );
    89→}
